#!/usr/bin/env python3
"""
Bug #1117: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['attention', 'matmul_4d_batch'], ['attention', 'matmul_4d_batch'], ['branch', 'two_conv_sum'], ['constant', 'mul_by_reciprocal'], ['broadcast', 'reciprocal_plus_one'], ['fusion', 'batchnorm_chain_small_eps']]
Dependencies: numpy jax
Run         : python unique_1117.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128, 1, 1])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128, 1, 1])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w6 = np.frombuffer(bytes.fromhex("b3c54a3e"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 128, 32, 32])
_w8 = np.frombuffer(bytes.fromhex("00000040"), dtype=np.float32).reshape([1])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w12 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w13 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w14 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w15 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w16 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 128, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_mm4d_out = jnp.matmul(x, _w0)
    n100_mm4d_out = jnp.matmul(n0_mm4d_out, _w1)
    n200_tcs_cv1 = (lax.conv_general_dilated(n100_mm4d_out, _w2, window_strides=[1, 1], padding=((0, 0), (0, 0)), lhs_dilation=(1,1), rhs_dilation=[1, 1], dimension_numbers=('NCHW','OIHW','NCHW'), feature_group_count=1) + jnp.reshape(_w3, [1,-1,1,1]))
    n200_tcs_cv2 = (lax.conv_general_dilated(n100_mm4d_out, _w4, window_strides=[1, 1], padding=((0, 0), (0, 0)), lhs_dilation=(1,1), rhs_dilation=[1, 1], dimension_numbers=('NCHW','OIHW','NCHW'), feature_group_count=1) + jnp.reshape(_w5, [1,-1,1,1]))
    n200_tcs_out = n200_tcs_cv1 + n200_tcs_cv2
    n300_mbr_mul = n200_tcs_out * _w6
    n300_mbr_out = n300_mbr_mul + _w7
    n400_rcs_ad = n300_mbr_out + _w8
    n400_rcs_rc = np.float32(1.0) / n400_rcs_ad
    n400_rcs_out = n400_rcs_rc * n300_mbr_out
    n500_bcs_bn1 = (lambda _x, _s, _b, _m, _v: jnp.reshape(_s, [1,-1]+[1]*(_x.ndim-2)) * ((_x - jnp.reshape(_m, [1,-1]+[1]*(_x.ndim-2))) / jnp.sqrt(jnp.reshape(_v, [1,-1]+[1]*(_x.ndim-2)) + np.float32(1.0000000116860974e-07))) + jnp.reshape(_b, [1,-1]+[1]*(_x.ndim-2)))(n400_rcs_out, _w9, _w10, _w11, _w12)
    n500_bcs_out = (lambda _x, _s, _b, _m, _v: jnp.reshape(_s, [1,-1]+[1]*(_x.ndim-2)) * ((_x - jnp.reshape(_m, [1,-1]+[1]*(_x.ndim-2))) / jnp.sqrt(jnp.reshape(_v, [1,-1]+[1]*(_x.ndim-2)) + np.float32(1.0000000116860974e-07))) + jnp.reshape(_b, [1,-1]+[1]*(_x.ndim-2)))(n500_bcs_bn1, _w13, _w14, _w15, _w16)
    return jnp.asarray(n500_bcs_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
